fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val dirs = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))
    val dist = Array(m) { Array(n) { LongArray(k.toInt() + 1) { Long.MAX_VALUE } } }
    dist[0][0][0] = 0
    val heap = PriorityQueue<Triple<Long, Int, Int>>(compareBy { it.first })
    heap.add(Triple(0L, 0, 0))

    while (heap.isNotEmpty()) {
        val (currentCost, i, j) = heap.poll()
        val currentK = (currentCost and 0xFFFF).toInt()
        val actualCost = currentCost shr 16
        if (i == m - 1 && j == n - 1) {
            return actualCost
        }
        if (actualCost > dist[i][j][currentK]) continue

        // Normal moves
        for (dir in dirs) {
            val ni = i + dir[0]
            val nj = j + dir[1]
            if (ni in 0 until m && nj in 0 until n) {
                val newCost = actualCost + grid[ni][nj]
                if (newCost < dist[ni][nj][currentK]) {
                    dist[ni][nj][currentK] = newCost
                    heap.add(Triple((newCost shl 16) + currentK, ni, nj))
                }
            }
        }

        // Teleport moves
        if (currentK < k) {
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (x == i && y == j) continue
                    if (grid[x][y] <= grid[i][j]) {
                        val newK = currentK + 1
                        if (actualCost < dist[x][y][newK]) {
                            dist[x][y][newK] = actualCost
                            heap.add(Triple((actualCost shl 16) + newK, x, y))
                        }
                    }
                }
