import java.util.PriorityQueue

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val dirs = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))

    // Priority queue: (cost, i, j, remainingK)
    val heap = PriorityQueue<LongArray>(compareBy { it[0] })
    heap.offer(longArrayOf(0, 0, 0, k))

    // Visited: (i, j, remainingK) -> min cost
    val visited = mutableMapOf<String, Long>()

    while (heap.isNotEmpty()) {
        val (cost, i, j, remainingK) = heap.poll()
        if (i.toInt() == m - 1 && j.toInt() == n - 1) {
            return cost
        }

        val key = "$i,$j,$remainingK"
        if (visited.containsKey(key) && visited[key]!! <= cost) {
            continue
        }
        visited[key] = cost

        // Try normal moves
        for (dir in dirs) {
            val ni = i + dir[0]
            val nj = j + dir[1]
            if (ni in 0 until m && nj in 0 until n) {
                val newCost = cost + grid[ni.toInt()][nj.toInt()]
                val newKey = "$ni,$nj,$remainingK"
                if (!visited.containsKey(newKey) || visited[newKey]!! > newCost) {
                    heap.offer(longArrayOf(newCost, ni, nj, remainingK))
                }
            }
        }

        // Try teleport if remainingK > 0
        if (remainingK > 0) {
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (x == i.toInt() && y == j.toInt()) continue
                    if (grid[x][y] <= grid[i.toInt()][j.toInt()]) {
                        val newKey = "$x,$y,${remainingK - 1}"
                        if (!visited.containsKey(newKey) || visited[newKey]!! > cost) {
                            heap.offer(longArrayOf(cost, x.toLong(), y.toLong(), remainingK - 1))
                        }
                    }
                }
            }
        }
    }

    return -1
}
