fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val dirs = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))
    val heap = PriorityQueue<LongArray>(compareBy { it[0] })
    heap.offer(longArrayOf(0, 0, 0, k)) // cost, i, j, remaining k

    val visited = Array(m) { Array(n) { LongArray(k.toInt() + 1) { Long.MAX_VALUE } } }
    visited[0][0][k.toInt()] = 0

    while (heap.isNotEmpty()) {
        val current = heap.poll()
        val cost = current[0]
        val i = current[1].toInt()
        val j = current[2].toInt()
        val remainingK = current[3].toInt()

        if (i == m - 1 && j == n - 1) {
            return cost
        }

        if (cost > visited[i][j][remainingK]) {
            continue
        }

        // Try normal moves
        for (dir in dirs) {
            val ni = i + dir[0]
            val nj = j + dir[1]
            if (ni in 0 until m && nj in 0 until n) {
                val newCost = cost + grid[ni][nj]
                if (newCost < visited[ni][nj][remainingK]) {
                    visited[ni][nj][remainingK] = newCost
                    heap.offer(longArrayOf(newCost, ni.toLong(), nj.toLong(), remainingK.toLong()))
                }
            }
        }

        // Try teleport if remainingK > 0
        if (remainingK > 0) {
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (x == i && y == j) continue
                    if (grid[x][y] <= grid[i][j]) {
                        val newK = remainingK - 1
                        if (cost < visited[x][y][newK]) {
                            visited[x][y][newK] = cost
                            heap.offer(longArrayOf(cost, x.toLong(), y.toLong(), newK.toLong()))
                        }
                    }
                }
            }
        }
    }

    return -1
}
