import java.util.PriorityQueue

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val directions = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))
    val visited = Array(m) { Array(n) { BooleanArray(k.toInt() + 1) } }
    val heap = PriorityQueue<Triple<Long, Int, Int>>(compareBy { it.first })
    heap.offer(Triple(0L, 0, 0))

    while (heap.isNotEmpty()) {
        val (cost, i, j) = heap.poll()
        val remainingK = cost.toInt() and 0xFFFF
        val actualCost = cost shr 16
        val x = i shr 8
        val y = i and 0xFF

        if (x == m - 1 && y == n - 1) {
            return actualCost
        }

        if (visited[x][y][remainingK]) continue
        visited[x][y][remainingK] = true

        for (dir in directions) {
            val nx = x + dir[0]
            val ny = y + dir[1]
            if (nx in 0 until m && ny in 0 until n) {
                val newCost = actualCost + grid[nx][ny]
                val newState = (nx shl 8) or ny
                if (!visited[nx][ny][remainingK]) {
                    heap.offer(Triple((newCost shl 16) or remainingK.toLong(), newState, remainingK))
                }
            }
        }

        if (remainingK < k) {
            for (nx in 0 until m) {
                for (ny in 0 until n) {
                    if (grid[nx][ny] <= grid[x][y] && (nx != x || ny != y)) {
                        val newK = remainingK + 1
                        if (newK <= k && !visited[nx][ny][newK]) {
                            val newState = (nx shl 8) or ny
                            heap.offer(Triple((actualCost shl 16) or newK.toLong(), newState, newK))
                        }
                    }
                }
            }
        }
    }

    return -1
}
