import java.util.PriorityQueue

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val directions = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))
    val visited = Array(m) { Array(n) { BooleanArray(k.toInt() + 1) } }
    val heap = PriorityQueue<State>(compareBy { it.cost })
    heap.offer(State(0, 0, 0, 0))

    while (heap.isNotEmpty()) {
        val current = heap.poll()
        if (current.i == m - 1 && current.j == n - 1) {
            return current.cost
        }
        if (visited[current.i][current.j][current.teleports]) continue
        visited[current.i][current.j][current.teleports] = true

        // Try normal moves
        for (dir in directions) {
            val ni = current.i + dir[0]
            val nj = current.j + dir[1]
            if (ni in 0 until m && nj in 0 until n) {
                val newCost = current.cost + grid[ni][nj]
                if (!visited[ni][nj][current.teleports]) {
                    heap.offer(State(ni, nj, newCost, current.teleports))
                }
            }
        }

        // Try teleport if possible
        if (current.teleports < k) {
            for (i in 0 until m) {
                for (j in 0 until n) {
                    if (i == current.i && j == current.j) continue
                    if (grid[i][j] <= grid[current.i][current.j]) {
                        val newTeleports = current.teleports + 1
                        if (!visited[i][j][newTeleports.toInt()]) {
                            heap.offer(State(i, j, current.cost, newTeleports))
                        }
                    }
                }
            }
        }
    }

    return -1
}

data class State(
    val i: Int,
    val j: Int,
    val cost: Long,
    val teleports: Long
